#include <bits/stdc++.h>
using namespace std;
int n,a[101];
int main(){
    cin>>n;
    for(int i=1;i<=n;i++)cin>>a[i];
    sort(a+1,a+n+1);
    int sum=0;
    for(int i=3;i<=n;i++){
        bool flag=true;
        for(int r=i-1;r>1;r--){
            if(!flag)break;
            for(int l=r-1;l>0;l--){
                if(a[r]+a[l]==a[i]){sum++;flag=false;break;}
            }
        }
    }
    cout<<sum;
    return 0;
}
